// Domain models shared across the LakeCrew frontend.
// These mirror the backend Prisma schema / surface contract.

export type Role = 'member' | 'coach';
export type Level = 'novice' | 'intermediate' | 'competitive';
export type BoatType = 'ONE_X' | 'TWO_X' | 'FOUR_PLUS' | 'EIGHT_PLUS';
export type BoatStatus = 'active' | 'maintenance' | 'retired';
export type SignupStatus = 'confirmed' | 'waitlist' | 'cancelled';

/** Display labels for boat types (1x / 2x / 4+ / 8+). */
export const BOAT_TYPE_LABELS: Record<BoatType, string> = {
  ONE_X: '1x',
  TWO_X: '2x',
  FOUR_PLUS: '4+',
  EIGHT_PLUS: '8+',
};

export interface User {
  id: string;
  email: string;
  role: Role;
  name?: string;
  level?: Level | null;
  createdAt?: string;
}

/** A club member as shown in the directory (alias of User, with optional attendance). */
export interface Member extends User {
  attendanceCount?: number;
}

export interface Boat {
  id: string;
  name: string;
  type: BoatType;
  seats: number;
  status: BoatStatus;
  createdAt?: string;
}

export interface PracticeBoat {
  id: string;
  practiceId: string;
  boatId: string;
  boat?: Boat;
}

export interface Signup {
  id: string;
  practiceId: string;
  userId: string;
  status: SignupStatus;
  user?: User;
  createdAt?: string;
}

export interface Practice {
  id: string;
  startsAt: string;
  capacity: number;
  notes?: string | null;
  boats?: Boat[];
  signups?: Signup[];
  confirmedCount?: number;
  waitlistCount?: number;
}

export interface ConditionLog {
  id: string;
  loggedOn: string;
  waterTempC: number;
  windKts: number;
  note?: string | null;
  userId?: string;
  user?: Pick<User, 'id' | 'name' | 'email'>;
  createdAt?: string;
}

/** Attendance record — a past practice the member had a confirmed signup for. */
export interface AttendanceEntry {
  practiceId: string;
  startsAt: string;
  status: SignupStatus;
}

export interface HomeData {
  latestCondition: ConditionLog | null;
  upcomingPractices: Practice[];
}

export interface ServiceSetting {
  service: string;
  label: string;
  configured: boolean;
  fields: { key: string; label: string; masked: string; secret?: boolean }[];
}
